def solve(landStartTime: Array[Long], landDuration: Array[Long], waterStartTime: Array[Long], waterDuration: Array[Long]): Long = {
    var minTime = Long.MaxValue

    for (i <- landStartTime.indices) {
        for (j <- waterStartTime.indices) {
            // Case 1: land first, then water
            val landEnd = landStartTime(i) + landDuration(i)
            val waterStart = math.max(waterStartTime(j), landEnd)
            val waterEnd = waterStart + waterDuration(j)
            val total1 = waterEnd

            // Case 2: water first, then land
            val waterEnd2 = waterStartTime(j) + waterDuration(j)
            val landStart2 = math.max(landStartTime(i), waterEnd2)
            val landEnd2 = landStart2 + landDuration(i)
            val total2 = landEnd2

            // Update minTime
            if (total1 < minTime) minTime = total1
            if (total2 < minTime) minTime = total2
        }
    }

    minTime
}
